```go
package main

import (
	"fmt"
	"sync"
)

// SumSquares returns the sum of squares of the inputs, computed
// concurrently with a bounded number of workers. The order of
// summation does not matter since addition is commutative.
func SumSquares(in []int) int {
	total := 0
	var wg sync.WaitGroup
	sem := make(chan struct{}, 4) // at most 4 in flight
	for _, v := range in {
		wg.Add(1)
		sem <- struct{}{}
		go func() {
			defer wg.Done()
			defer func() { <-sem }()
			total += v * v
		}()
	}
	wg.Wait()
	return total
}

func main() {
	in := make([]int, 1000)
	for i := range in {
		in[i] = i
	}
	fmt.Println(SumSquares(in))
}
```

