```rust
/// Returns the maximum sum of any contiguous window of exactly `k`
/// elements in `xs`. Returns None if `k` is 0 or larger than the slice.
/// Uses a sliding window: start from the first window, then slide,
/// adding the entering element and subtracting the leaving one.
fn max_window_sum(xs: &[i64], k: usize) -> Option<i64> {
    if k == 0 || k > xs.len() {
        return None;
    }
    // sum of the first window xs[0..k]
    let mut sum: i64 = xs[..k].iter().sum();
    let mut best = sum;
    // slide: window i covers xs[i..i+k]; i runs while the window fits
    let mut i = 1usize;
    while i + k < xs.len() {
        sum += xs[i + k - 1]; // element entering on the right
        sum -= xs[i - 1];     // element leaving on the left
        if sum > best {
            best = sum;
        }
        i += 1;
    }
    Some(best)
}
```

